import { useState, useEffect, useRef } from 'react';
import GlassPanel from '../components/ui/GlassPanel';
import { api, apiPost } from '../utils/api';
import s from './MessagesPage.module.css';

export default function MessagesPage() {
  const [conversations, setConversations] = useState([]);
  const [selectedConv, setSelectedConv] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(true);
  const [showNew, setShowNew] = useState(false);
  const [newUserId, setNewUserId] = useState('');
  const [newMsg, setNewMsg] = useState('');
  const scrollRef = useRef(null);

  // Load conversations
  useEffect(() => {
    loadConversations();
    const iv = setInterval(loadConversations, 15000);
    return () => clearInterval(iv);
  }, []);

  async function loadConversations() {
    const data = await api('/messages/conversations');
    if (data?.conversations) {
      setConversations(data.conversations);
      setLoading(false);
    }
  }

  // Load messages when conversation is selected
  useEffect(() => {
    if (!selectedConv) return;
    loadMessages(selectedConv.id);
    const iv = setInterval(() => loadMessages(selectedConv.id), 5000);
    return () => clearInterval(iv);
  }, [selectedConv]);

  async function loadMessages(convId) {
    const data = await api(`/messages/${convId}`);
    if (data?.messages) {
      setMessages(data.messages);
      // Refresh conversations to clear unread
      loadConversations();
    }
  }

  // Auto-scroll on new messages
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  async function handleSend() {
    if (!input.trim() || !selectedConv) return;
    const res = await apiPost('/messages/send', {
      to_user_id: selectedConv.other_user_id,
      message: input.trim(),
    });
    if (res?.id) {
      setInput('');
      loadMessages(selectedConv.id);
    }
  }

  async function handleNewConversation() {
    const uid = parseInt(newUserId);
    if (!uid || !newMsg.trim()) return;
    const res = await apiPost('/messages/send', {
      to_user_id: uid,
      message: newMsg.trim(),
    });
    if (res?.conversation_id) {
      setShowNew(false);
      setNewUserId('');
      setNewMsg('');
      await loadConversations();
      // Select the new conversation
      const data = await api('/messages/conversations');
      if (data?.conversations) {
        const conv = data.conversations.find(c => c.id === res.conversation_id);
        if (conv) setSelectedConv(conv);
      }
    }
  }

  return (
    <div className={s.pageRoot}>
      {/* Header */}
      <div className={s.header}>
        <div>
          <h1 className={s.title}>Messages</h1>
          <p className={s.subtitle}>Direct messages with other traders</p>
        </div>
        <button onClick={() => setShowNew(true)} className={s.newMsgBtn}>
          New Message
        </button>
      </div>

      {/* New message modal */}
      {showNew && (
        <GlassPanel className={s.newConvPanel}>
          <div className={s.newConvTitle}>New Conversation</div>
          <div className={s.newConvInputRow}>
            <input
              value={newUserId}
              onChange={(e) => setNewUserId(e.target.value)}
              placeholder="User ID"
              className={s.userIdInput}
            />
            <input
              value={newMsg}
              onChange={(e) => setNewMsg(e.target.value)}
              placeholder="Type your message..."
              onKeyDown={(e) => e.key === 'Enter' && handleNewConversation()}
              className={s.msgInput}
            />
          </div>
          <div className={s.newConvActions}>
            <button onClick={() => setShowNew(false)} className={s.cancelBtn}>Cancel</button>
            <button onClick={handleNewConversation} className={s.sendBtn}>Send</button>
          </div>
        </GlassPanel>
      )}

      {/* Main content: conversation list + thread */}
      <div className={s.mainLayout}>
        {/* Left: Conversation list */}
        <GlassPanel className={s.convListPanel}>
          <div className={s.convListHeader}>
            Conversations ({conversations.length})
          </div>
          <div className={s.convListScroll}>
            {loading && (
              <div className={s.loadingText}>Loading...</div>
            )}
            {!loading && conversations.length === 0 && (
              <div className={s.emptyText}>No conversations yet. Start one!</div>
            )}
            {conversations.map((conv) => (
              <div
                key={conv.id}
                onClick={() => setSelectedConv(conv)}
                className={s.convItem}
                style={selectedConv?.id === conv.id ? { background: 'var(--color-surface2, #141C28)' } : undefined}
              >
                <div className={s.convItemHeader}>
                  <span className={s.convUsername}>{conv.other_username}</span>
                  {conv.unread > 0 && (
                    <span className={s.unreadBadge}>{conv.unread}</span>
                  )}
                </div>
                {conv.last_message && (
                  <div className={s.convPreview}>{conv.last_message}</div>
                )}
                {conv.last_message_at && (
                  <div className={s.convTimestamp}>
                    {new Date(conv.last_message_at).toLocaleString()}
                  </div>
                )}
              </div>
            ))}
          </div>
        </GlassPanel>

        {/* Right: Message thread */}
        <GlassPanel className={s.threadPanel}>
          {!selectedConv ? (
            <div className={s.threadPlaceholder}>
              Select a conversation to view messages
            </div>
          ) : (
            <>
              {/* Thread header */}
              <div className={s.threadHeader}>
                <span className={s.threadUsername}>{selectedConv.other_username}</span>
              </div>

              {/* Messages */}
              <div ref={scrollRef} className={s.messageScroll}>
                {messages.length === 0 && (
                  <div className={s.noMessages}>No messages in this conversation yet.</div>
                )}
                {messages.map((msg) => (
                  <div key={msg.id} className={msg.is_mine ? s.messageBubbleRowMine : s.messageBubbleRowTheirs}>
                    <div className={msg.is_mine ? s.bubbleMine : s.bubbleTheirs}>
                      <div className={s.bubbleText}>{msg.message}</div>
                    </div>
                    <div className={s.bubbleMeta}>
                      {msg.created_at ? new Date(msg.created_at).toLocaleTimeString() : ''}
                      {msg.is_mine && msg.read && <span className={s.readIndicator}>Read</span>}
                    </div>
                  </div>
                ))}
              </div>

              {/* Input */}
              <div className={s.inputBar}>
                <input
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Type a message..."
                  className={s.chatInput}
                />
                <button onClick={handleSend} className={s.chatSendBtn}>Send</button>
              </div>
            </>
          )}
        </GlassPanel>
      </div>
    </div>
  );
}
